insert into courses (id, name, description, distance, difficulty, elevation, location, region, rating, review_count, coordinates, tags) values
  ('a1000001-0000-0000-0000-000000000001', '여의도 한강공원 코스', '여의도 한강공원을 따라 달리는 평탄한 코스. 벚꽃 시즌에 특히 인기가 많습니다.', 5.2, 'easy', 12, '여의도 한강공원', '서울 영등포구', 4.8, 342, '[{"lat":37.5283,"lng":126.9322},{"lat":37.5265,"lng":126.9410}]', '{"평지","한강","야경"}'),
  ('a1000001-0000-0000-0000-000000000002', '반포 한강공원 코스', '반포대교 달빛무지개분수를 감상하며 달리는 야경 코스.', 7.0, 'easy', 8, '반포 한강공원', '서울 서초구', 4.7, 289, '[{"lat":37.5091,"lng":126.9948},{"lat":37.5120,"lng":127.0100}]', '{"평지","한강","야경","분수"}'),
  ('a1000001-0000-0000-0000-000000000003', '북한산 둘레길 코스', '북한산 둘레길을 따라 자연 속에서 트레일러닝을 즐길 수 있는 코스.', 10.5, 'hard', 320, '북한산 둘레길', '서울 강북구', 4.9, 178, '[{"lat":37.6584,"lng":126.9780},{"lat":37.6610,"lng":126.9850}]', '{"트레일","산","자연","고급"}'),
  ('a1000001-0000-0000-0000-000000000004', '뚝섬 한강공원 코스', '뚝섬유원지역에서 출발하는 한강변 러닝 코스. 넓은 트랙이 매력.', 6.3, 'easy', 5, '뚝섬 한강공원', '서울 광진구', 4.6, 256, '[{"lat":37.5316,"lng":127.0660},{"lat":37.5340,"lng":127.0750}]', '{"평지","한강","넓은트랙"}'),
  ('a1000001-0000-0000-0000-000000000005', '올림픽공원 순환 코스', '올림픽공원 내 순환 도로를 따라 달리는 쾌적한 코스.', 8.0, 'medium', 45, '올림픽공원', '서울 송파구', 4.7, 412, '[{"lat":37.5209,"lng":127.1230},{"lat":37.5180,"lng":127.1300}]', '{"공원","순환","쾌적"}'),
  ('a1000001-0000-0000-0000-000000000006', '성수~잠실 한강 코스', '성수대교에서 잠실대교까지 한강 남측 도로를 따라 달리는 롱런 코스.', 12.0, 'medium', 15, '성수~잠실 한강변', '서울 성동구', 4.5, 198, '[{"lat":37.5405,"lng":127.0490},{"lat":37.5180,"lng":127.0900}]', '{"한강","장거리","다리"}');
