  ('b2000001-0000-0000-0000-000000000002', '반포 야경 러닝 크루', '반포대교 분수를 보면서 달려요. 매주 수요일 7시 반!', 'a1000001-0000-0000-0000-000000000002', '2026-04-13', '19:30', '5:30~6:00', 7.0, 10, '반포 한강공원 달빛광장', '서울 서초구', '{"야경","중급","정기러닝"}', 'upcoming', true, '매주 수요일'),
  ('b2000001-0000-0000-0000-000000000003', '주말 북한산 트레일런!', '토요일 아침 북한산 둘레길 트레일런! 경험자 추천.', 'a1000001-0000-0000-0000-000000000003', '2026-04-12', '07:00', '7:00~8:00', 10.5, 6, '북한산 둘레길 입구', '서울 강북구', '{"트레일런","상급","주말"}', 'full', false, null),
  ('b2000001-0000-0000-0000-000000000004', '올림픽공원 새벽 러닝', '새벽 5시 반 올림픽공원에서 출발합니다!', 'a1000001-0000-0000-0000-000000000005', '2026-04-14', '05:30', '5:00~5:30', 8.0, 12, '올림픽공원 평화의문', '서울 송파구', '{"새벽러닝","중급","공원"}', 'upcoming', true, '매주 월/수/금'),
  ('b2000001-0000-0000-0000-000000000005', '뚝섬 초보 러닝 모임', '처음 러닝 시작하는 분들을 위한 모임!', 'a1000001-0000-0000-0000-000000000004', '2026-04-15', '18:30', '7:00~8:00', 3.0, 15, '뚝섬유원지역 2번 출구', '서울 광진구', '{"초보환영","워크런","한강"}', 'upcoming', false, null);
